def get_brujula_fixed_indicators() -> list[dict]:
    items: list[dict] = []
    for index, item in enumerate(BRUJULA_FIXED_INDICATORS, start=1):
        current = dict(item)
        current["id"] = index
        current["orden"] = int(current.get("orden") or index)
        items.append(current)
    return items
